-- One-time seed of the Annual Breakdown history (2018–2025), generated
-- from Victor's "Annual Breakdown" Google Sheet CSV export. Read-only
-- historical record; leaf line items only (parent subtotals recomputed at
-- render). See migration 0022_annual_breakdown_history.sql.
-- Household: fb0f52d2-cd2d-46af-874f-229711ba7b93
on conflict (household_id, kind, group_label, line_label, year) do update
set amount_cents = excluded.amount_cents,
    group_sort = excluded.group_sort,
    line_sort = excluded.line_sort,
    updated_at = now();
